exercises.solutionCode:
function maxSumSubarray(nums, k) {
  let sum = 0;
  let best = -Infinity;
  for (let i = 0; i < nums.length; i++) {
    sum += nums[i];
    if (i >= k) sum -= nums[i - k];
    if (i >= k - 1) best = Math.max(best, sum);
  }
  return best;
}

