exercises.solutionCode:
function kthSmallest(nums, k) {
  const a = [...nums]; let lo = 0; let hi = a.length - 1; const target = k - 1;
  while (lo <= hi) {
    const pivot = a[hi]; let p = lo;
    for (let i = lo; i < hi; i++) if (a[i] <= pivot) [a[i], a[p]] = [a[p], a[i]], p++;
    [a[p], a[hi]] = [a[hi], a[p]];
    if (p === target) return a[p];
    if (p < target) lo = p + 1; else hi = p - 1;
  }
}

