function maxConcurrent(intervals) {
  const events = intervals.flatMap(([s,e]) => [[s,1],[e,-1]]).sort((a,b) => a[0]-b[0] || a[1]-b[1]);
  let active = 0, best = 0;
  for (const [, delta] of events) { active += delta; best = Math.max(best, active); }
  return best;
}

