function kmpIndexOf(text, pattern) {
  if (!pattern) return 0;
  const lps = Array(pattern.length).fill(0);
  for (let i=1,j=0; i<pattern.length;) { if (pattern[i]===pattern[j]) lps[i++]=++j; else if (j) j=lps[j-1]; else i++; }
  for (let i=0,j=0; i<text.length;) { if (text[i]===pattern[j]) { i++; j++; if (j===pattern.length) return i-j; } else if (j) j=lps[j-1]; else i++; }
  return -1;
}

