function countComponents(n, edges) {
  const parent = Array.from({length:n}, (_,i)=>i); let count=n;
  const find = x => parent[x]===x ? x : parent[x]=find(parent[x]);
  for (const [a,b] of edges) { const ra=find(a), rb=find(b); if (ra!==rb) { parent[ra]=rb; count--; } }
  return count;
}

