function rangeSum(nums, left, right) {
  const bit = Array(nums.length+1).fill(0);
  const add=(i,v)=>{ for(i++;i<bit.length;i+=i&-i) bit[i]+=v; };
  const sum=i=>{ let out=0; for(i++;i>0;i-=i&-i) out+=bit[i]; return out; };
  nums.forEach((v,i)=>add(i,v));
  return sum(right)-(left ? sum(left-1) : 0);
}

