exercises.solutionCode:
function bellmanFord(n, edges, source) {
  const d=Array(n).fill(Infinity); d[source]=0;
  for(let pass=1;pass<n;pass++){ let changed=false; for(const [u,v,w] of edges) if(d[u]!==Infinity && d[u]+w<d[v]){d[v]=d[u]+w;changed=true;} if(!changed)break; }
  return d.map(v=>v===Infinity?null:v);
}

