function maxFlow(capacity, source, sink) {
  const r=capacity.map(row=>[...row]); let flow=0;
  while(true){ const parent=Array(r.length).fill(-1); parent[source]=source; const q=[source]; for(let h=0;h<q.length&&parent[sink]===-1;h++){ const u=q[h]; for(let v=0;v<r.length;v++) if(parent[v]===-1&&r[u][v]>0){parent[v]=u;q.push(v);} }
    if(parent[sink]===-1) return flow; let add=Infinity; for(let v=sink;v!==source;v=parent[v]) add=Math.min(add,r[parent[v]][v]);
    for(let v=sink;v!==source;v=parent[v]){r[parent[v]][v]-=add;r[v][parent[v]]+=add;} flow+=add;
  }
}
